The condition `n % 2 == 1` filters for odd numbers; change it to `n % 2 == 0` to keep even numbers.

def get_evens(nums):
    return [n for n in nums if n % 2 == 0]

The bug is a missing base case for n = 0 (and no guard against negatives), so inputs less than or equal to 0 recurse forever.

def factorial(n):
    if n < 0:
        raise ValueError("Factorial is not defined for negative numbers")
    if n == 0:
        return 1
    return n * factorial(n - 1)

def is_palindrome(s):
    cleaned = ''.join(c.lower() for c in s if c.isalnum())
    return cleaned == cleaned[::-1]

def fizzbuzz(n):
    result = []
    for i in range(1, n + 1):
        if i % 3 == 0 and i % 5 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return result
